function setMatrixZeroes(matrix) {
  const rows = matrix.length;
  const cols = matrix[0]?.length ?? 0;
  const zeroRows = new Set();
  const zeroCols = new Set();

  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      if (matrix[r][c] === 0) {
        zeroRows.add(r);
        zeroCols.add(c);
