```js
function normalizePhoneNumber(input, defaultCountry = 'US') {
  if (input == null) {
    return null;
  }

  const raw = String(input).trim();
  if (!raw) {
    return null;
  }

  const extensionMatch = raw.match(/(?:ext\.?|x|extension)\s*(\d+)\s*$/i);
  const extension = extensionMatch ? extensionMatch[1] : null;
  const withoutExtension = extensionMatch
    ? raw.slice(0, extensionMatch.index).trim()
    : raw;

  if (/[A-Za-z]/.test(withoutExtension)) {
    throw new Error('Phone number contains invalid characters');
  }

  let normalized = withoutExtension.replace(/[\s().-]/g, '');

  if (!/^\+?\d+$/.test(normalized)) {
    throw new Error('Phone number contains unsupported characters');
  }

  if (normalized.startsWith('00')) {
    normalized = `+${normalized.slice(2)}`;
  }

  if (!normalized.startsWith('+')) {
    if (defaultCountry === 'US') {
      if (normalized.length === 10) {
        normalized = `+1${normalized}`;
      } else if (normalized.length === 11 && normalized.startsWith('1')) {
        normalized = `+${normalized}`;
      } else {
        throw new Error('Invalid US phone number length');
      }
    } else {
      throw new Error(`Unsupported default country: ${defaultCountry}`);
    }
  }

  const digits = normalized.slice(1);
  if (digits.length < 8 || digits.length > 15) {
    throw new Error('Phone number must contain 8 to 15 digits');
  }

  return extension ? `${normalized}x${extension}` : normalized;
}

module.exports = { normalizePhoneNumber };
```

