function isValidIPv4(input) {
  if (typeof input !== 'string' || input !== input.trim() || input.length === 0) {
    return false;
  }

  const parts = input.split('.');
  if (parts.length !== 4) {
    return false;
  }

  return parts.every((part) => {
    if (!/^\d+$/.test(part)) {
      return false;
    }
    if (part.length > 1 && part[0] === '0') {
      return false;
    }

    const value = Number(part);
    return value >= 0 && value <= 255;
  });
