function flattenObject(obj) {
  const result = {};

  function escapeKey(key) {
    return String(key).replace(/\./g, '\\.')
  }

  function walk(value, path) {
    if (value === null || typeof value !== 'object') {
      if (path) result[path] = value;
      return;
    }

    if (Array.isArray(value)) {
      if (!path && value.length === 0) return;
      if (value.length === 0) {
        result[path] = [];
        return;
      }

      value.forEach((item, index) => {
        const nextPath = path ? `${path}.${index}` : String(index);
        walk(item, nextPath);
      });
      return;
    }

    const entries = Object.entries(value);

    if (!path && entries.length === 0) return;
    if (path && entries.length === 0) {
      result[path] = {};
      return;
    }

    for (const [key, child] of entries) {
      const safeKey = escapeKey(key);
      const nextPath = path ? `${path}.${safeKey}` : safeKey;
      walk(child, nextPath);
    }
  }

  if (obj === null || typeof obj !== 'object' || Array.isArray(obj)) {
    throw new TypeError('flattenObject expects a plain object');
  }

  walk(obj, '');
  return result;
}
```

**Array representation**
- Arrays are flattened using numeric indexes in the path.
- Example: `{ items: ['a', 'b'] }` becomes `{ 'items.0': 'a', 'items.1': 'b' }`.
- Empty arrays are preserved at their path, e.g. `{ items: [] }` becomes `{ items: [] }`.
- Object keys containing literal dots are escaped as `\.` so they remain distinguishable.

