function parseCsvLine(line) {
  if (typeof line !== 'string') {
    throw new TypeError('parseCsvLine expects a string');
  }

  if (line === '') {
    return [''];
  }

  const fields = [];
  let field = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const char = line[i];

    if (inQuotes) {
      if (char === '"') {
        if (line[i + 1] === '"') {
          field += '"';
          i++;
        } else {
          inQuotes = false;
        }
      } else {
        field += char;
      }
      continue;
    }

    if (char === ',') {
      fields.push(field);
      field = '';
      continue;
    }

    if (char === '"') {
      if (field !== '') {
        throw new Error(`Malformed CSV line: unexpected quote at index ${i}`);
      }
      inQuotes = true;
      continue;
    }

    field += char;
  }

  if (inQuotes) {
    throw new Error('Malformed CSV line: unmatched quote');
  }

  fields.push(field);
  return fields;
}

module.exports = { parseCsvLine };
```

