function binarySearchRange(nums, target) {
  function findFirst() {
    let left = 0;
    let right = nums.length - 1;
    let answer = -1;

    while (left <= right) {
      const mid = left + Math.floor((right - left) / 2);

      if (nums[mid] >= target) {
        if (nums[mid] === target) answer = mid;
        right = mid - 1;
      } else {
        left = mid + 1;
      }
    }

    return answer;
  }

  function findLast() {
    let left = 0;
    let right = nums.length - 1;
    let answer = -1;

    while (left <= right) {
      const mid = left + Math.floor((right - left) / 2);

      if (nums[mid] <= target) {
        if (nums[mid] === target) answer = mid;
        left = mid + 1;
      } else {
        right = mid - 1;
      }
    }

    return answer;
  }

  return [findFirst(), findLast()];
}

