```js
function compareVersions(a, b) {
  const pa = parseVersion(a);
  const pb = parseVersion(b);

  if (!pa.valid && !pb.valid) return 0;
  if (!pa.valid) return -1;
  if (!pb.valid) return 1;

  const len = Math.max(pa.numbers.length, pb.numbers.length);
  for (let i = 0; i < len; i++) {
    const na = pa.numbers[i] ?? 0;
    const nb = pb.numbers[i] ?? 0;
    if (na > nb) return 1;
    if (na < nb) return -1;
  }

  if (pa.prerelease.length === 0 && pb.prerelease.length > 0) return 1;
  if (pa.prerelease.length > 0 && pb.prerelease.length === 0) return -1;

  const preLen = Math.max(pa.prerelease.length, pb.prerelease.length);
  for (let i = 0; i < preLen; i++) {
    const ida = pa.prerelease[i];
    const idb = pb.prerelease[i];

    if (ida === undefined) return -1;
    if (idb === undefined) return 1;

    const aNum = /^\d+$/.test(ida);
    const bNum = /^\d+$/.test(idb);

    if (aNum && bNum) {
      const na = Number(ida);
      const nb = Number(idb);
      if (na > nb) return 1;
      if (na < nb) return -1;
      continue;
    }

    if (aNum && !bNum) return -1;
    if (!aNum && bNum) return 1;

    if (ida > idb) return 1;
    if (ida < idb) return -1;
  }

  return 0;
}

function parseVersion(version) {
  if (typeof version !== 'string' || version.trim() !== version || version === '') {
    return { valid: false };
  }

  const match = version.match(
    /^(\d+(?:\.\d+)*)(?:-([0-9A-Za-z-]+(?:\.[0-9A-Za-z-]+)*))?(?:\+[0-9A-Za-z-]+(?:\.[0-9A-Za-z-]+)*)?$/
  );

  if (!match) return { valid: false };

  const numbers = match[1].split('.').map(Number);
  const prerelease = match[2] ? match[2].split('.') : [];

  return {
    valid: true,
    numbers,
    prerelease,
  };
}
```

