const assert = require('assert');

assert.strictEqual(compareVersions('1.10.0', '1.2.9'), 1, 'larger minor wins');
assert.strictEqual(compareVersions('1.2.0', '1.2'), 0, 'missing patch treated as zero');
assert.strictEqual(compareVersions('1.2', '1.2.1'), -1, 'missing patch lower than explicit larger patch');
assert.strictEqual(compareVersions('01.002.0003', '1.2.3'), 0, 'leading zeros normalize');
assert.strictEqual(compareVersions('1.0.0', '1.0.0'), 0, 'equal versions');
assert.strictEqual(compareVersions('1.0', '1.0.0.0'), 0, 'different segment lengths with trailing zeros are equal');
assert.strictEqual(compareVersions('1.0.0.1', '1.0.0'), 1, 'extra non-zero segment wins');
assert.strictEqual(compareVersions('1.0.0-alpha', '1.0.0'), -1, 'prerelease lower than release');
assert.strictEqual(compareVersions('1.0.0-alpha.1', '1.0.0-alpha.beta'), -1, 'numeric prerelease lower than non-numeric');
assert.strictEqual(compareVersions('1.0.0-beta', '1.0.0-alpha'), 1, 'lexical prerelease comparison');
assert.strictEqual(compareVersions('1.0.0-alpha', '1.0.0-alpha.1'), -1, 'shorter prerelease set is lower');
assert.strictEqual(compareVersions('1.0.0+build1', '1.0.0+build2'), 0, 'build metadata ignored');
assert.strictEqual(compareVersions('1..0', '1.0.0'), -1, 'invalid format sorts below valid');
assert.strictEqual(compareVersions('v1.0.0', '1.0.0'), -1, 'invalid format sorts below valid');
assert.strictEqual(compareVersions('', '   '), 0, 'two invalid versions compare equal deterministically');

