```js
function wordWrap(text, maxWidth) {
  if (!Number.isInteger(maxWidth) || maxWidth < 1) {
    throw new Error('maxWidth must be a positive integer');
  }
  if (typeof text !== 'string') {
    throw new TypeError('text must be a string');
  }
  if (text === '') {
    return '';
  }

  return text
    .split('\n')
    .map(wrapParagraph)
    .join('\n');

  function wrapParagraph(paragraph) {
    const trailingSpaces = (paragraph.match(/ +$/) || [''])[0];
    const content = paragraph.trim();

    if (content === '') {
      return paragraph;
    }

    const words = content.split(/ +/);
    const lines = [];
    let current = '';

    for (const word of words) {
      if (current === '') {
        if (word.length <= maxWidth) {
          current = word;
        } else {
          pushChunks(word, lines);
        }
        continue;
      }

      if (current.length + 1 + word.length <= maxWidth) {
        current += ' ' + word;
        continue;
      }

      lines.push(current);
      if (word.length <= maxWidth) {
        current = word;
      } else {
        pushChunks(word, lines);
        current = '';
      }
    }

    if (current !== '') {
      lines.push(current);
    }

    if (trailingSpaces) {
      if (lines.length === 0) {
        lines.push('');
      }
      let i = lines.length - 1;
      let remaining = trailingSpaces;
      while (remaining.length > 0) {
        const available = maxWidth - lines[i].length;
        if (available === 0) {
          lines.push('');
          i += 1;
          continue;
        }
        const chunk = remaining.slice(0, available);
        lines[i] += chunk;
        remaining = remaining.slice(chunk.length);
      }
    }

    return lines.join('\n');
  }

  function pushChunks(word, lines) {
    for (let i = 0; i < word.length; i += maxWidth) {
      lines.push(word.slice(i, i + maxWidth));
    }
  }
}

module.exports = { wordWrap };
```

