function buildTree(items) {
  if (!Array.isArray(items)) {
    throw new TypeError('items must be an array');
  }

  const nodes = new Map();
  const roots = [];
  const errors = {
    duplicateIds: [],
    missingParents: [],
    cycles: [],
  };

  for (let i = 0; i < items.length; i++) {
    const item = items[i];

    if (item == null || typeof item !== 'object' || Array.isArray(item)) {
      throw new TypeError(`items[${i}] must be an object`);
    }

    if (!Object.prototype.hasOwnProperty.call(item, 'id')) {
      throw new TypeError(`items[${i}].id is required`);
    }

    const { id, parentId = null } = item;

    if (id === null || id === undefined) {
      throw new TypeError(`items[${i}].id must not be null or undefined`);
    }

    if (nodes.has(id)) {
      errors.duplicateIds.push(id);
      continue;
    }

    nodes.set(id, {
      id,
      parentId,
      children: [],
    });
  }

  const visiting = new Set();
  const visited = new Set();
  const cycleIds = new Set();

  function detectCycle(id) {
    if (visited.has(id) || cycleIds.has(id)) return;
    if (visiting.has(id)) {
      cycleIds.add(id);
      return;
    }

    const node = nodes.get(id);
    if (!node) return;

    visiting.add(id);

    if (node.parentId !== null && node.parentId !== undefined && nodes.has(node.parentId)) {
      detectCycle(node.parentId);
      if (cycleIds.has(node.parentId)) {
        cycleIds.add(id);
      }
    }

    visiting.delete(id);
    visited.add(id);
  }

  for (const id of nodes.keys()) {
    detectCycle(id);
  }

  errors.cycles = [...cycleIds];

  for (const node of nodes.values()) {
    if (cycleIds.has(node.id)) {
      roots.push(node);
      continue;
    }

    if (node.parentId === null || node.parentId === undefined) {
      roots.push(node);
      continue;
    }

    const parent = nodes.get(node.parentId);

    if (!parent) {
      errors.missingParents.push({ id: node.id, parentId: node.parentId });
      roots.push(node);
      continue;
    }

    if (cycleIds.has(parent.id)) {
      roots.push(node);
      continue;
    }

    parent.children.push(node);
  }

  return {
    roots,
    errors,
  };
}

module.exports = { buildTree };
