function parseDateISO(input) {
  if (typeof input !== 'string') {
    return { ok: false, error: 'Input must be a string' };
  }

  if (input === '') {
    return { ok: false, error: 'Input cannot be empty' };
  }

  if (input !== input.trim()) {
    return { ok: false, error: 'Input must not contain leading or trailing whitespace' };
  }

  const match = /^(\d{4})-(\d{2})-(\d{2})$/.exec(input);
  if (!match) {
    return { ok: false, error: 'Date must be in strict YYYY-MM-DD format' };
  }

  const year = Number(match[1]);
  const month = Number(match[2]);
  const day = Number(match[3]);

  if (month < 1 || month > 12) {
    return { ok: false, error: 'Month must be between 01 and 12' };
  }

  const isLeapYear =
    (year % 4 === 0 && year % 100 !== 0) || year % 400 === 0;

  const daysInMonth = [
    31,
    isLeapYear ? 29 : 28,
    31,
    30,
    31,
    30,
    31,
    31,
    30,
    31,
    30,
    31,
  ];

  const maxDay = daysInMonth[month - 1];
  if (day < 1 || day > maxDay) {
    return { ok: false, error: `Day must be between 01 and ${String(maxDay).padStart(2, '0')} for month ${String(month).padStart(2, '0')}` };
  }

  return {
    ok: true,
    value: {
      year,
      month,
      day,
      date: new Date(Date.UTC(year, month - 1, day)),
    },
  };
}

module.exports = { parseDateISO };
