function relativePath(from, to) {
  if (typeof from !== 'string' || typeof to !== 'string') {
    throw new TypeError('relativePath expects string arguments');
  }

  const fromStyle = detectStyle(from);
  const toStyle = detectStyle(to);

  if (!fromStyle || !toStyle) {
    throw new Error('Both paths must be absolute');
  }

  if (fromStyle !== toStyle) {
    throw new Error('Cannot compute relative path between different path styles');
  }

  const sep = fromStyle === 'windows' ? '\\' : '/';
  const fromInfo = splitAbsolute(from, fromStyle);
  const toInfo = splitAbsolute(to, toStyle);

  if (fromStyle === 'windows' && fromInfo.root.toLowerCase() !== toInfo.root.toLowerCase()) {
    throw new Error('Cannot compute relative path across different Windows drives');
  }

  if (fromStyle === 'posix' && fromInfo.root !== toInfo.root) {
    throw new Error('Cannot compute relative path across different roots');
  }

  const fromParts = fromInfo.parts;
  const toParts = toInfo.parts;

  let shared = 0;
  while (
    shared < fromParts.length &&
    shared < toParts.length &&
    samePart(fromParts[shared], toParts[shared], fromStyle)
  ) {
    shared++;
  }

  const up = new Array(fromParts.length - shared).fill('..');
  const down = toParts.slice(shared);
  const result = [...up, ...down].join(sep);

  return result || '.';
}

function detectStyle(path) {
  if (/^[A-Za-z]:[\\/]/.test(path)) return 'windows';
  if (/^\//.test(path)) return 'posix';
  return null;
}

function splitAbsolute(path, style) {
  const normalized = normalizeAbsolute(path, style);

  if (style === 'windows') {
    const root = normalized.slice(0, 2);
    const rest = normalized.slice(3);
    return {
      root,
      parts: rest ? rest.split('\\') : [],
    };
  }

  const rest = normalized.slice(1);
  return {
    root: '/',
    parts: rest ? rest.split('/') : [],
  };
}

function normalizeAbsolute(path, style) {
  let normalized = path.trim();

  if (style === 'windows') {
    normalized = normalized.replace(/\//g, '\\');
    normalized = normalized.replace(/\\+/g, '\\');
    const root = normalized.slice(0, 3);
    const rest = normalized
      .slice(3)
      .split('\\')
      .filter(Boolean);
    return root + rest.join('\\');
  }

  normalized = normalized.replace(/\/+/g, '/');
  const parts = normalized.split('/').filter(Boolean);
  return '/' + parts.join('/');
}

function samePart(a, b, style) {
  return style === 'windows' ? a.toLowerCase() === b.toLowerCase() : a === b;
}

// tests
function runTests() {
  const cases = [
    {
      name: 'same path',
      actual: relativePath('/a/b', '/a/b'),
      expected: '.',
    },
    {
      name: 'sibling directories',
      actual: relativePath('/a/b', '/a/c'),
      expected: '../c',
    },
    {
      name: 'nested child',
      actual: relativePath('/a/b', '/a/b/c/d'),
      expected: 'c/d',
    },
    {
      name: 'nested parent',
      actual: relativePath('/a/b/c/d', '/a/b'),
      expected: '../..',
    },
    {
      name: 'root to nested path',
      actual: relativePath('/', '/usr/local'),
      expected: 'usr/local',
    },
    {
      name: 'nested path to root',
      actual: relativePath('/usr/local/bin', '/'),
      expected: '../../..',
    },
    {
      name: 'trailing slashes',
      actual: relativePath('/a/b/', '/a/b/c/'),
      expected: 'c',
    },
    {
      name: 'windows mixed separators',
      actual: relativePath('C:\\a\\b', 'C:/a/c/d'),
      expected: '..\\c\\d',
    },
  ];

  for (const test of cases) {
    if (test.actual !== test.expected) {
      throw new Error(`${test.name}: expected ${test.expected}, got ${test.actual}`);
    }
  }

  assertThrows(
    () => relativePath('a/b', '/a/b'),
    'Both paths must be absolute',
    'invalid from path'
  );

  assertThrows(
    () => relativePath('/a/b', 'a/b'),
    'Both paths must be absolute',
    'invalid to path'
  );

  assertThrows(
    () => relativePath('C:\\a', 'D:\\b'),
    'Cannot compute relative path across different Windows drives',
    'different windows drives'
  );

  console.log('All tests passed');
}

function assertThrows(fn, expectedMessage, name) {
  try {
    fn();
    throw new Error(`${name}: expected function to throw`);
  } catch (error) {
    if (error.message !== expectedMessage) {
      throw new Error(`${name}: expected "${expectedMessage}", got "${error.message}"`);
    }
  }
}

runTests();
```

Notes:
- Returns `.` when both absolute paths are the same.
- Rejects non-absolute input.
- Supports POSIX paths and Windows drive-letter absolute paths.
- Normalizes trailing slashes and mixed `/` + `\\` separators for Windows inputs.
- Rejects cross-drive Windows comparisons because no single relative path exists there.

