/**
 * Sort an array of objects by multiple rules.
 *
 * Assumptions:
 * - `rules` is an array of `{ key, direction }` objects.
 * - `direction` may be `"asc"` or `"desc"` and defaults to `"asc"`.
 * - Missing fields (`undefined` or absent keys) sort after defined values in ascending
 *   order and before defined values in descending order.
 * - `null` is treated as a normal value, not as missing.
 * - Mixed primitive value types are compared with these rules:
 *   1. If both values are numbers, compare numerically.
 *   2. If both values are strings, compare lexicographically.
 *   3. If both values are booleans, compare `false < true`.
 *   4. If values are different types, compare their string representations.
 * - The sort is stable: if all rules compare equal, original order is preserved.
 * - The input array is not mutated.
 */
function sortByMultiple(items, rules) {
  if (!Array.isArray(items)) {
    throw new TypeError('items must be an array');
  }

  if (!Array.isArray(rules)) {
    throw new TypeError('rules must be an array');
  }

  if (items.length <= 1 || rules.length === 0) {
    return items.slice();
  }

  const normalizedRules = rules.map((rule, index) => {
    if (!rule || typeof rule.key !== 'string' || rule.key.length === 0) {
      throw new TypeError(`rules[${index}].key must be a non-empty string`);
    }

    const direction = rule.direction == null ? 'asc' : rule.direction;
    if (direction !== 'asc' && direction !== 'desc') {
      throw new TypeError(`rules[${index}].direction must be "asc" or "desc"`);
    }

    return { key: rule.key, direction };
  });

  return items
    .map((item, index) => ({ item, index }))
    .sort((a, b) => {
      for (const rule of normalizedRules) {
        const result = compareValues(a.item[rule.key], b.item[rule.key], rule.direction);
        if (result !== 0) {
          return result;
        }
      }

      return a.index - b.index;
    })
    .map(entry => entry.item);
}

function compareValues(a, b, direction) {
  const aMissing = a === undefined;
  const bMissing = b === undefined;

  if (aMissing || bMissing) {
    if (aMissing && bMissing) return 0;
    return direction === 'asc'
      ? (aMissing ? 1 : -1)
      : (aMissing ? -1 : 1);
  }

  let result = 0;

  if (typeof a === 'number' && typeof b === 'number') {
    result = a - b;
  } else if (typeof a === 'string' && typeof b === 'string') {
    result = a.localeCompare(b);
  } else if (typeof a === 'boolean' && typeof b === 'boolean') {
    result = Number(a) - Number(b);
  } else {
    result = String(a).localeCompare(String(b));
  }

  if (result === 0) return 0;
  return direction === 'asc' ? result : -result;
}

module.exports = { sortByMultiple };
