function parseBoolean(input) {
  if (typeof input === 'boolean') return input;

  if (typeof input === 'string') {
    const normalized = input.trim().toLowerCase();

    if (normalized === 'true' || normalized === '1' || normalized === 'yes') {
      return true;
    }

    if (normalized === 'false' || normalized === '0' || normalized === 'no') {
      return false;
    }

    if (normalized === '') {
      throw new TypeError('Invalid boolean value: empty string');
    }

    throw new TypeError(`Invalid boolean value: ${input}`);
  }

  if (typeof input === 'number') {
    if (Number.isNaN(input)) {
      throw new TypeError('Invalid boolean value: NaN');
    }

    if (input === 1) return true;
    if (input === 0) return false;

    throw new TypeError(`Invalid boolean value: ${input}`);
  }

  throw new TypeError(`Invalid boolean value type: ${typeof input}`);
}

module.exports = { parseBoolean };
