  });

  test('one node with self-cycle', () => {
    const a = new ListNode(1);
    a.next = a;
    expect(detectCycle(a)).toBe(true);
  });

  test('multiple nodes without cycle', () => {
    const a = new ListNode(1);
    const b = new ListNode(2);
    const c = new ListNode(3);
    a.next = b;
    b.next = c;

    expect(detectCycle(a)).toBe(false);
