function serializeForm(fields) {
  if (!Array.isArray(fields) || fields.length === 0) return '';

  const parts = [];

  for (const field of fields) {
    if (!field || typeof field !== 'object') {
      throw new TypeError('Each field must be an object with name and value properties');
    }

    const name = field.name == null ? '' : String(field.name);
    const value = field.value == null ? '' : String(field.value);

    parts.push(`${encodeURIComponent(name)}=${encodeURIComponent(value)}`);
  }

  return parts.join('&');
}

module.exports = { serializeForm };
```

Encoding behavior:
- Uses `encodeURIComponent` for both names and values.
- Spaces become `%20` (not `+`).
- `null` and `undefined` are serialized as empty strings.
- Empty names are allowed and serialize as `=value`.
- Repeated field names are preserved in input order.
- Empty input returns `''`.
- Non-array input or non-object entries throw `TypeError`.

