        { name: 'lastName', value: 'Lovelace' },
      ]),
      'firstName=Ada&lastName=Lovelace'
    );
  });

  it('preserves repeated field names in order', () => {
    assert.strictEqual(
      serializeForm([
        { name: 'tag', value: 'js' },
        { name: 'tag', value: 'node' },
