        { name: '', value: 'value' },
      ]),
      '=value'
    );
  });

  it('allows empty values', () => {
    assert.strictEqual(
      serializeForm([
        { name: 'empty', value: '' },
      ]),
      'empty='
    );
  });

  it('encodes spaces as %20', () => {
    assert.strictEqual(
      serializeForm([
