      ]),
      'a%26b%3Dc=x%2Fy%3Fz%231'
    );
  });

  it('encodes Unicode characters', () => {
    assert.strictEqual(
      serializeForm([
        { name: 'café', value: '你好 🌍' },
      ]),
      'caf%C3%A9=%E4%BD%A0%E5%A5%BD%20%F0%9F%8C%8D'
    );
