function descriptiveStats(numbers) {
  if (!Array.isArray(numbers)) {
    throw new TypeError('numbers must be an array');
  }

  if (numbers.length === 0) {
    return {
      count: 0,
      min: null,
      max: null,
      mean: null,
      median: null,
      mode: null,
      range: null,
    };
  }

  for (const value of numbers) {
    if (typeof value !== 'number' || Number.isNaN(value)) {
      throw new TypeError('numbers must contain only valid numbers');
    }
  }

  const sorted = [...numbers].sort((a, b) => a - b);
  const count = sorted.length;
  const min = sorted[0];
  const max = sorted[count - 1];
  const sum = sorted.reduce((total, n) => total + n, 0);
  const mean = sum / count;

  const middle = Math.floor(count / 2);
  const median =
    count % 2 === 0
      ? (sorted[middle - 1] + sorted[middle]) / 2
      : sorted[middle];

  const frequencies = new Map();
  for (const n of sorted) {
    frequencies.set(n, (frequencies.get(n) || 0) + 1);
  }

  let highestFrequency = 0;
  for (const freq of frequencies.values()) {
    if (freq > highestFrequency) highestFrequency = freq;
  }

  const modeCandidates = [...frequencies.entries()]
    .filter(([, freq]) => freq === highestFrequency)
    .map(([value]) => value)
    .sort((a, b) => a - b);

  // Defined behavior:
  // - If every value appears once, there is no mode => null
  // - If multiple values tie for highest frequency, return all of them as an array
  // - If exactly one value has highest frequency, return that value
  let mode = null;
  if (highestFrequency > 1) {
    mode = modeCandidates.length === 1 ? modeCandidates[0] : modeCandidates;
  }

  return {
    count,
    min,
    max,
    mean,
    median,
    mode,
    range: max - min,
  };
}
