function nearestPalindrome(n) {
  if (typeof n !== 'string' || !/^[0-9]+$/.test(n) || n.length === 0) {
    throw new TypeError('n must be a non-empty string of digits');
  }
  if (n.length > 1 && n[0] === '0') {
    throw new TypeError('n must not have leading zeros');
  }

  const trimLeadingZeros = (s) => {
    const trimmed = s.replace(/^0+/, '');
    return trimmed === '' ? '0' : trimmed;
  };

  const compareNumStr = (a, b) => {
    const aa = trimLeadingZeros(a);
    const bb = trimLeadingZeros(b);
    if (aa.length !== bb.length) return aa.length < bb.length ? -1 : 1;
    if (aa === bb) return 0;
    return aa < bb ? -1 : 1;
  };

  const addOne = (s) => {
    let carry = 1;
    let out = '';
    for (let i = s.length - 1; i >= 0; i--) {
      const digit = s.charCodeAt(i) - 48 + carry;
      if (digit >= 10) {
        out = '0' + out;
        carry = 1;
      } else {
        out = String.fromCharCode(48 + digit) + out;
        carry = 0;
      }
    }
    return carry ? '1' + out : out;
  };

  const subOne = (s) => {
    if (s === '0') return null;
    let borrow = 1;
    let out = '';
    for (let i = s.length - 1; i >= 0; i--) {
      let digit = s.charCodeAt(i) - 48 - borrow;
      if (digit < 0) {
        digit += 10;
        borrow = 1;
      } else {
        borrow = 0;
      }
      out = String.fromCharCode(48 + digit) + out;
    }
    return trimLeadingZeros(out);
  };

  const mirrorFromLeft = (left, oddLength) => {
    const right = left
      .slice(0, oddLength ? left.length - 1 : left.length)
      .split('')
      .reverse()
      .join('');
    return trimLeadingZeros(left + right);
  };

  const absDiff = (a, b) => {
    let x = trimLeadingZeros(a);
    let y = trimLeadingZeros(b);
    if (compareNumStr(x, y) < 0) {
      [x, y] = [y, x];
    }

    let borrow = 0;
    let out = '';
    let i = x.length - 1;
    let j = y.length - 1;

    while (i >= 0) {
      let digit = (x.charCodeAt(i) - 48) - borrow;
      const sub = j >= 0 ? y.charCodeAt(j) - 48 : 0;
      if (digit < sub) {
        digit += 10;
        borrow = 1;
      } else {
        borrow = 0;
      }
      out = String.fromCharCode(48 + (digit - sub)) + out;
      i--;
      j--;
    }

    return trimLeadingZeros(out);
  };

  const chooseCloser = (best, candidate) => {
    if (candidate === n) return best;
    if (best == null) return candidate;

    const bestDiff = absDiff(best, n);
    const candDiff = absDiff(candidate, n);
    const diffCmp = compareNumStr(candDiff, bestDiff);

    if (diffCmp < 0) return candidate;
    if (diffCmp > 0) return best;
    return compareNumStr(candidate, best) < 0 ? candidate : best;
  };

  if (n.length === 1) {
    return n === '0' ? '1' : String.fromCharCode(n.charCodeAt(0) - 1);
  }

  const oddLength = n.length % 2 === 1;
  const leftLen = Math.ceil(n.length / 2);
  const left = n.slice(0, leftLen);

  const candidates = new Set();
  candidates.add(mirrorFromLeft(left, oddLength));

  const incLeft = addOne(left);
  candidates.add(mirrorFromLeft(incLeft, oddLength));

  const decLeft = subOne(left);
  if (decLeft !== null) {
    candidates.add(mirrorFromLeft(decLeft, oddLength));
  }

  candidates.add('1' + '0'.repeat(n.length - 1) + '1');
  candidates.add('9'.repeat(n.length - 1) || '0');

  let best = null;
  for (const candidate of candidates) {
    best = chooseCloser(best, candidate);
  }
  return best;
}

// Tests
(function () {
  const assert = (condition, message) => {
    if (!condition) throw new Error(message);
  };

  const cases = [
    ['1', '0'],                                  // single digit
    ['9', '8'],                                  // single digit upper end
    ['10', '9'],                                 // power of ten
    ['100', '99'],                               // power of ten, tie -> smaller
    ['1000', '999'],                             // larger power of ten, tie -> smaller
    ['11', '9'],                                 // already palindromic
    ['121', '111'],                              // already palindromic, tie -> smaller
    ['99', '101'],                               // already palindromic near boundary
    ['123', '121'],                              // ordinary case
    ['1283', '1331'],                            // ordinary even length
    ['1001', '999'],                             // palindrome, tie across digit lengths
    ['123456789876543210', '123456789987654321'] // very large input
  ];

  for (const [input, expected] of cases) {
    const actual = nearestPalindrome(input);
    assert(
      actual === expected,
      `nearestPalindrome(${JSON.stringify(input)}) => ${actual}, expected ${expected}`
    );
  }

  const invalid = [
    '',
    '001',
    '12a',
    '-1',
    123,
    null,
    undefined,
  ];

  for (const input of invalid) {
    let threw = false;
    try {
      nearestPalindrome(input);
    } catch (err) {
      threw = err instanceof TypeError;
    }
    assert(threw, `Expected TypeError for ${JSON.stringify(input)}`);
  }

  console.log('All tests passed');
})();
```

Notes:
- Returns the closest palindrome as a string.
- Breaks ties by returning the smaller palindrome.
- Uses string arithmetic only, so it stays safe for very large inputs.

