```js
function removeComments(code) {
  if (code === '') return '';

  let result = '';
  let i = 0;
  let state = 'normal';
  let stringQuote = '';

  while (i < code.length) {
    const char = code[i];
    const next = code[i + 1];

    if (state === 'lineComment') {
      if (char === '\n') {
        result += char;
        state = 'normal';
      }
      i += 1;
      continue;
    }

    if (state === 'blockComment') {
      if (char === '*' && next === '/') {
        state = 'normal';
        i += 2;
        continue;
      }
      i += 1;
      continue;
    }

    if (state === 'string') {
      result += char;

      if (char === '\\') {
        if (i + 1 < code.length) {
          result += code[i + 1];
          i += 2;
          continue;
        }
      } else if (char === stringQuote) {
        state = 'normal';
        stringQuote = '';
      }

      i += 1;
      continue;
    }

    if (char === '"' || char === "'") {
      state = 'string';
      stringQuote = char;
      result += char;
      i += 1;
      continue;
    }

    if (char === '/' && next === '/') {
      state = 'lineComment';
      i += 2;
      continue;
    }

    if (char === '/' && next === '*') {
      state = 'blockComment';
      i += 2;
      continue;
    }

    result += char;
    i += 1;
  }

  return result;
}

module.exports = { removeComments };
