function romanToInt(input) {
  if (typeof input !== 'string') {
    throw new TypeError('Roman numeral must be a string');
  }

  const s = input.trim();
  if (!s) {
    throw new Error('Roman numeral cannot be empty');
  }
  if (!/^[ivxlcdm]+$/i.test(s)) {
    throw new Error('Roman numeral contains invalid characters');
  }

  const roman = s.toUpperCase();
  const values = {
    I: 1,
    V: 5,
    X: 10,
    L: 50,
    C: 100,
    D: 500,
    M: 1000,
  };
  const allowedSubtractive = new Set(['IV', 'IX', 'XL', 'XC', 'CD', 'CM']);

  let total = 0;
  let i = 0;
  let repeatCount = 1;

  while (i < roman.length) {
    const current = roman[i];
    const next = roman[i + 1];
    const currentValue = values[current];
    const nextValue = next ? values[next] : 0;

    if (i > 0) {
      if (roman[i] === roman[i - 1]) {
        repeatCount += 1;
      } else {
        repeatCount = 1;
      }

      if ((current === 'V' || current === 'L' || current === 'D') && repeatCount > 1) {
        throw new Error(`Symbol ${current} cannot repeat`);
      }

      if ((current === 'I' || current === 'X' || current === 'C' || current === 'M') && repeatCount > 3) {
        throw new Error(`Symbol ${current} cannot repeat more than 3 times`);
      }
    }

    if (next && currentValue < nextValue) {
      const pair = current + next;

      if (!allowedSubtractive.has(pair)) {
        throw new Error(`Invalid subtractive pair: ${pair}`);
      }

      if (repeatCount > 1) {
        throw new Error(`Invalid repetition before subtractive pair: ${pair}`);
      }

      total += nextValue - currentValue;
      i += 2;
      repeatCount = 1;
      continue;
    }

    total += currentValue;
    i += 1;
  }

  const canonical = intToRoman(total);
  if (canonical !== roman) {
    throw new Error(`Malformed Roman numeral: ${input}`);
  }

  return total;
}

function intToRoman(num) {
  const table = [
    [1000, 'M'],
    [900, 'CM'],
    [500, 'D'],
    [400, 'CD'],
    [100, 'C'],
    [90, 'XC'],
    [50, 'L'],
    [40, 'XL'],
    [10, 'X'],
    [9, 'IX'],
    [5, 'V'],
    [4, 'IV'],
    [1, 'I'],
  ];

  let result = '';
  let remaining = num;

  for (const [value, symbol] of table) {
    while (remaining >= value) {
      result += symbol;
      remaining -= value;
    }
  }

  return result;
}

module.exports = { romanToInt };
```

