// 3. one item fits
assert.strictEqual(knapsack01([{ weight: 3, value: 50 }], 3), 50);

// 4. one item does not fit
assert.strictEqual(knapsack01([{ weight: 4, value: 50 }], 3), 0);

// 5. multiple items with same optimal value
