  knapsack01(
    [
      { weight: 0, value: 5 },
      { weight: 0, value: 7 },
      { weight: 2, value: 10 },
    ],
    2
  ),
  22
);

// 7. invalid negative weight
assert.throws(
  () => knapsack01([{ weight: -1, value: 5 }], 10),
  /weight must be a non-negative integer/
);

// 8. larger capacity case
