594.answer:
A JWT has three dot-separated parts: `header.payload.signature`.

- **Header**: metadata about the token, usually the signing algorithm (`alg`) and token type (`typ`). Example: `{"alg":"HS256","typ":"JWT"}`
- **Payload**: the claims/data, such as `sub`, `exp`, `iat`, `role`, etc. This is readable by anyone holding the token unless the JWT is encrypted.
- **Signature**: proves integrity. It is typically computed over `base64url(header) + "." + base64url(payload)` using the specified algorithm and a secret/private key. If header or payload changes, signature verification fails.

Important: base64url-decoding a JWT does **not** verify it. It only parses the visible contents.

```js
function decodeJwtParts(jwt) {
  const parts = jwt.split('.');
  if (parts.length < 2) {
    throw new Error('Invalid JWT');
  }

  const base64UrlDecode = (input) => {
    let base64 = input.replace(/-/g, '+').replace(/_/g, '/');
    const pad = base64.length % 4;
    if (pad) base64 += '='.repeat(4 - pad);
    return Buffer.from(base64, 'base64').toString('utf8');
  };

  return {
    header: JSON.parse(base64UrlDecode(parts[0])),
    payload: JSON.parse(base64UrlDecode(parts[1])),
  };
}

// Example:
// const decoded = decodeJwtParts(token);
// console.log(decoded.header, decoded.payload);
```

Browser version:

```js
function decodeJwtParts(jwt) {
  const parts = jwt.split('.');
  if (parts.length < 2) {
    throw new Error('Invalid JWT');
  }

  const base64UrlDecode = (input) => {
    let base64 = input.replace(/-/g, '+').replace(/_/g, '/');
    const pad = base64.length % 4;
    if (pad) base64 += '='.repeat(4 - pad);
    return decodeURIComponent(
      atob(base64)
        .split('')
        .map((c) => `%${c.charCodeAt(0).toString(16).padStart(2, '0')}`)
        .join('')
    );
  };

  return {
    header: JSON.parse(base64UrlDecode(parts[0])),
    payload: JSON.parse(base64UrlDecode(parts[1])),
  };
}
```

