600.answer:
Markdown headings use 1-6 `#` characters at the start of a line: `#` for level 1, `##` for level 2, through `######` for level 6. Higher-level headings define broader sections, and deeper headings belong under the nearest previous heading with a smaller level. For example, an `###` heading is a child of the most recent `##` or `#` heading above it.

```js
function parseMarkdownToc(markdown) {
  const lines = markdown.split(/\r?\n/);
  const root = [];
  const stack = [];

  for (const line of lines) {
    const match = line.match(/^(#{1,6})\s+(.+?)\s*#*\s*$/);
    if (!match) continue;

    const level = match[1].length;
    const title = match[2].trim();
    const node = { title, level, children: [] };

    while (stack.length && stack[stack.length - 1].level >= level) {
      stack.pop();
    }

    if (stack.length === 0) {
      root.push(node);
    } else {
      stack[stack.length - 1].children.push(node);
    }

    stack.push(node);
  }

  return root;
}
```

