```python
from typing import Any, Callable, Dict, Iterable, List, Tuple


def process_records(
    records: Iterable[Dict[str, Any]],
    save_record: Callable[[Dict[str, Any]], Any],
) -> Dict[str, Any]:
    normalized = _normalize_records(records)
    valid_records, invalid_records = _validate_records(normalized)
    persisted = _persist_records(valid_records, save_record)
    return _build_report(persisted, invalid_records)


def _normalize_records(records: Iterable[Dict[str, Any]]) -> List[Dict[str, Any]]:
    normalized = []
    for record in records:
        item = dict(record)
        if "name" in item and isinstance(item["name"], str):
            item["name"] = item["name"].strip()
        if "email" in item and isinstance(item["email"], str):
            item["email"] = item["email"].strip().lower()
        normalized.append(item)
    return normalized


def _validate_records(
    records: Iterable[Dict[str, Any]],
) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]]]:
    valid = []
    invalid = []

    for record in records:
        if _is_valid_record(record):
            valid.append(record)
        else:
            invalid.append(record)

    return valid, invalid


def _is_valid_record(record: Dict[str, Any]) -> bool:
    name = record.get("name")
    email = record.get("email")
    return bool(name) and isinstance(email, str) and "@" in email


def _persist_records(
    records: Iterable[Dict[str, Any]],
    save_record: Callable[[Dict[str, Any]], Any],
) -> List[Dict[str, Any]]:
    persisted = []

    for record in records:
        result = save_record(record)
        persisted.append({"record": record, "result": result})

    return persisted


def _build_report(
    persisted: Iterable[Dict[str, Any]],
    invalid_records: Iterable[Dict[str, Any]],
) -> Dict[str, Any]:
    persisted = list(persisted)
    invalid_records = list(invalid_records)

    return {
        "saved_count": len(persisted),
        "invalid_count": len(invalid_records),
        "saved": persisted,
        "invalid": invalid_records,
    }
``` 

